);

INSERT INTO products (id, title, price, originalPrice, imageUrl, amazonUrl, affiliateUrl, description, rating, category, createdAt) VALUES ('a4f0bcb5-6f90-40b6-8539-d5d8db5271c9', 'Voltas 243V Vectra Elite 2 ton 3 star inverter Split AC|4-IN-1 Adjustable mode|Energy Efficient|High ambient Cooling-cools even at 52°C|Anti dust filter with Anti-microbial coating|Copper Coil| White', '₹44,500 ', '₹65,990', 'https://m.media-amazon.com/images/I/61nv5TqjBoL._SL1500_.jpg', 'https://www.amazon.in/Voltas-Vectra-Elite-Cooling-cools-Anti-microbial/dp/B0BBFTT3YL/ref=sr_1_1?_encoding=UTF8&content-id=amzn1.sym.58c90a12-100b-4a2f-8e15-7c06f1abe2be&dib=eyJ2IjoiMSJ9.JBrMSo92pLno0VV6VGCGV9y4jdrSZOSpK17DWbkakp_C_4BcGPWSY_KOwVeyUCsAS5yta_xi3l_JumI0zXlq14A-9L0UCKB1x0slk593fVqY1-WAZ-mbovitPZxMosxp4bPSoE2lApSbQ8kBwCoc3Q.3oRcgv5RUu0OK3bi9vGRAJLHNa0z6814QK5WcFO5KfM&dib_tag=se&pd_rd_r=a8f177b0-7e9d-47b6-b70b-525806dc1f37&pd_rd_w=hqE3V&pd_rd_wg=Qla6A&qid=1782395259&refinements=p_85%3A10440599031&rps=1&s=kitchen&sr=1-1&th=1', 'https://www.amazon.in/Voltas-Vectra-Elite-Cooling-cools-Anti-microbial/dp/B0BBFTT3YL/ref=sr_1_1?_encoding=UTF8&content-id=amzn1.sym.58c90a12-100b-4a2f-8e15-7c06f1abe2be&dib=eyJ2IjoiMSJ9.JBrMSo92pLno0VV6VGCGV9y4jdrSZOSpK17DWbkakp_C_4BcGPWSY_KOwVeyUCsAS5yta_xi3l_JumI0zXlq14A-9L0UCKB1x0slk593fVqY1-WAZ-mbovitPZxMosxp4bPSoE2lApSbQ8kBwCoc3Q.3oRcgv5RUu0OK3bi9vGRAJLHNa0z6814QK5WcFO5KfM&dib_tag=se&pd_rd_r=a8f177b0-7e9d-47b6-b70b-525806dc1f37&pd_rd_w=hqE3V&pd_rd_wg=Qla6A&qid=1782395259&refinements=p_85%3A10440599031&rps=1&s=kitchen&sr=1-1&th=1', 'About this item
Split AC with inverter compressor: Variable speed compressor which adjusts power depending on heat load. Convertible / adjustable with 4 cooling modes through remote control to operate in different tonnages for different cooling needs (20% to 120% capacity).
Capacity: 2 ton Suitable for large sized rooms (151 sq.ft to 200 sq.ft) & Ambient Temperature: 52 degree Celsius.
Energy Rating: 3 Star | Annual Energy Consumption 1220.59 kWh/year; Maximum cooling capacity: 6050W | ISSER Value: 3.81. BEE Label Validity Period: 1st July 2022 - 31st Dec 2025. Note: The current star rating is based on the 2025 BEE guidelines. Under the new 2026 BEE guidelines (effective from 1st Jan 2026), this product will be rated one star lower.
Manufacturer Warranty: 5 Years Comprehensive Warranty on the Product for the purchases done from 19th Sep''25 to 31st Dec''25, 10 Years Warranty on Inverter Compressor, 5 Years Warranty on PCB for the purchases done from Jan 2025 onwards
Copper Condenser Coil: Better cooling and requires low maintenance, Prevents from rust & corrosion; Increase durability; Uninterrupted cooling.
Key Features: Stabilizer free operation within 230 Voltage range; Digital Temperature Display ; Noise Level: 47 / 45 / 43 / 38 dB
Special Features: Anti Dust, Antimicrobial Protection, Anti-Corrosive Coating, LED Display, Self Diagnosis, Sleep Mode, Turbo, Remote Lock, Low Gas Diagnosis, Auto Restart, Anti Fungal', '3.9', 'Appliances', '2026-06-25T13:53:54.276Z');
INSERT INTO products (id, title, price, originalPrice, imageUrl, amazonUrl, affiliateUrl, description, rating, category, createdAt) VALUES ('4530850d-e2bb-4c5f-a53d-4c0c0934cc3c', 'Xiaomi Power Bank 4i 20000mAh 33W Super Fast Charging PD |Smart 12 Layer Protection|Type C Input & Output|Triple Output Ports|Supports Android,Apple, Tablets, Earbuds,Watch(MI Powerbank),Black', '₹2,299 ', '₹3,999', 'https://m.media-amazon.com/images/I/41vBAaU8clL._SX679_.jpg', 'https://www.amazon.in/Xiaomi-20000mAh-Charging-Delivery-Supports/dp/B0DCZ3WDTB/?_encoding=UTF8&pd_rd_w=QNFpH&content-id=amzn1.sym.0776cdfa-c115-4a21-b5e4-abfbef29849f&pf_rd_p=0776cdfa-c115-4a21-b5e4-abfbef29849f&pf_rd_r=G5EFC3A9S0DYE6457VV0&pd_rd_wg=ljxZr&pd_rd_r=db92e053-dcd8-4d2f-bb1d-eafeffbaf688&th=1', 'https://www.amazon.in/Xiaomi-20000mAh-Charging-Delivery-Supports/dp/B0DCZ3WDTB/?_encoding=UTF8&pd_rd_w=QNFpH&content-id=amzn1.sym.0776cdfa-c115-4a21-b5e4-abfbef29849f&pf_rd_p=0776cdfa-c115-4a21-b5e4-abfbef29849f&pf_rd_r=G5EFC3A9S0DYE6457VV0&pd_rd_wg=ljxZr&pd_rd_r=db92e053-dcd8-4d2f-bb1d-eafeffbaf688&th=1', '33W Fast Charging Support - High-speed charging with two-way fast charge via Type-C port; charges compatible devices quickly and efficiently. Superior Output
Smart Protection Safety & Compatibility - Equipped with 12-layer advanced circuit protection and compatible with a wide range of Android, iOS, and USB-C devices including smartphones, earbuds, and wearables.
Massive 20000mAh Battery Capacity - Reliable power backup for smartphones, tablets, wearables, and more; perfect for travel and long usage days. Retains 80% capacity after 300 cycles of usage.
Smart Power Delivery (PD) Support - Advanced PD 3.0 ensures intelligent and optimized charging for all your devices, including iPhones, Android phones, and tablets.
Durable Design - Premium matte black finish with anti-smudge texture, compact and portable build with a high-quality, durable shell.
Triple Port Output - Equipped with 2 USB-A and 1 USB-C output ports to charge three devices simultaneously, boosting convenience and productivity.
12 months Warranty with Pan Indian presence of service centres', '4.2', 'Electronics', '2026-06-25T13:57:23.116Z');
